SELECT id, site_code AS siteCode, agent_id AS agentId, agent_account AS agentAccount, user_account AS userAccount, user_id AS userId, user_name AS userName, vip_grade_code AS vipGradeCode, order_no AS orderNo, adjust_way AS adjustWay, adjust_type AS adjustType, activity_template AS activityTemplate, activity_id AS activityId, currency_code AS currencyCode, platform_currency_code AS platformCurrencyCode, adjust_amount AS adjustAmount, running_water_multiple AS runningWaterMultiple, certificate_address AS certificateAddress, apply_reason AS applyReason, apply_time AS applyTime, applicant AS applicant, audit_datetime AS auditDatetime, audit_id AS auditId, audit_remark AS auditRemark, audit_status AS auditStatus, review_operation AS reviewOperation, lock_status AS lockStatus, locker AS locker, IF(locker = #{vo.operator}, -1, 1) as lockStatus1 FROM user_platform_coin_manual_up_down_record WHERE site_code = #{vo.siteCode} AND review_operation = #{vo.reviewOperation}
AND apply_time >= #{vo.applyStartTime}
AND apply_time <= #{vo.applyEndTime}
AND user_account = #{vo.userAccount}
AND order_no = #{vo.orderNo}
AND lock_status = #{vo.lockStatus}
AND locker = #{vo.locker}
ORDER BY lockStatus1 ASC, lock_status ASC, apply_time ASC

